    "modules.dev_guide": "Modul erstellen — Entwicklerhandbuch",
    "modules.dev_guide_title": "Eigenes Modul erstellen",
    "modules.dev_guide_subtitle": "Eine praktische 10-Minuten-Anleitung, um OpenConstructionERP um Geschäftsfunktionen zu erweitern.",
    "modules.back_to_modules": "Zurück zu Module & Marktplatz",
    "modules.dev_prereq_title": "Voraussetzungen",
    "modules.dev_prereq_intro": "Halte das Folgende bereit, bevor du startest. Wenn die App lokal läuft, hast du bereits alles, was du brauchst.",
    "modules.dev_prereq_verify": "Öffne http://localhost:5173 und melde dich an. Stelle sicher, dass die Modul-Seite lädt, bevor du loslegst.",
    "modules.dev_demo_title": "Hello World — dein erstes Modul in 3 Minuten",
    "modules.dev_demo_intro": "Minimales End-to-End-Modul mit einem Greeting-Endpoint. Kopiere die vier Blöcke unten, starte das Backend neu und rufe die Route mit curl auf — das ist der komplette Kreislauf.",
    "modules.dev_demo_step1": "1. Ordner erstellen",
    "modules.dev_demo_step2": "2. backend/app/modules/hello_world/__init__.py (leere Datei)",
    "modules.dev_demo_step3": "3. backend/app/modules/hello_world/manifest.py",
    "modules.dev_demo_step4": "4. backend/app/modules/hello_world/router.py",
    "modules.dev_demo_step5": "5. Backend neu starten und testen",
    "modules.dev_demo_note": "Das war alles — keine main.py-Änderung, kein Registry-Import, keine Migration. Der Modul-Loader entdeckt den Ordner, liest das Manifest und mountet den Router. Das Modul taucht außerdem automatisch unter Module & Marktplatz auf.",
    "modules.dev_what": "Was ist ein Modul?",
    "modules.dev_what_desc": "OpenConstructionERP v4.3 enthält mehr als 110 Module. Jede Geschäftsfunktion — LV, BIM Hub, Terminplan, CDE, regionale LV-Pakete, KI-Tools — ist ein eigenständiges Modul. Ein Modul kann REST-Routen, Datenbanktabellen, UI-Seiten, Validierungsregeln, Übersetzungen oder eine beliebige Kombination davon hinzufügen. Jedes Modul lässt sich aktivieren, deaktivieren, installieren oder ersetzen, ohne den Kern anzufassen.",
    "modules.dev_what_backend": "Nur Backend",
    "modules.dev_what_backend_ex": "z. B. ein neuer API-Connector oder Webhook-Empfänger",
    "modules.dev_what_frontend": "Nur Frontend",
    "modules.dev_what_frontend_ex": "z. B. eine regionale LV-Austausch-UI oder ein spezieller Bericht",
    "modules.dev_what_full": "Full-Stack",
    "modules.dev_what_full_ex": "die meisten echten Features — Routen, UI und eine DB-Migration",
    "modules.dev_backend_title": "Backend-Modul — in 5 Minuten",
    "modules.dev_backend_intro": "Alles startet mit dem Template im Repo. Der Modul-Loader entdeckt automatisch alles, was du unter backend/app/modules/ ablegst — kein manuelles Verdrahten von Routen oder Migrationen nötig.",
    "modules.dev_step_copy": "Vom Template ableiten",
    "modules.dev_step_manifest": "Manifest bearbeiten",
    "modules.dev_step_router": "Router hinzufügen",
    "modules.dev_step_models": "Modelle & Schemas hinzufügen (optional)",
    "modules.dev_step_validation": "Validierungsregeln deklarieren",
    "modules.dev_step_restart": "Neu starten und aktivieren",
    "modules.dev_backend_ref": "Referenzimplementierungen: backend/app/modules/boq/ und backend/app/modules/projects/.",
    "modules.dev_tree_title": "Dateistruktur — wo was hingehört",
    "modules.dev_tree_intro": "Backend- und Frontend-Module folgen einer strikten Konvention. Halte dich daran und Loader + Registry verdrahten alles automatisch; weiche ab und es bricht an überraschenden Stellen.",
    "modules.dev_tree_backend": "Backend-Modul",
    "modules.dev_tree_frontend": "Frontend-Modul",
    "modules.dev_tree_note": "Alle Dateien außer manifest.* sind optional — starte mit dem kleinsten Satz und füge weitere hinzu, sobald das Modul wächst.",
    "modules.dev_db_title": "Datenbank-Migrationen",
    "modules.dev_db_intro": "Wenn dein Modul Tabellen hinzufügt oder verändert, musst du eine Migration mitliefern. Das Projekt nutzt Alembic — Autogenerate ist dein Freund, aber prüfe das Ergebnis immer.",
    "modules.dev_db_step1": "Modell definieren",
    "modules.dev_db_step2": "Modell beim App-Start registrieren",
    "modules.dev_db_step3": "Migration generieren",
    "modules.dev_db_step4": "Ausliefern",
    "modules.dev_db_warn": "Tabellennamen immer mit dem Modul-Slug (oe_my_module_*) präfixen, um Kollisionen zu vermeiden. Spalten niemals in einer einzelnen Migration entfernen — neue Spalte anlegen, befüllen, dann in einem späteren Release entfernen.",
    "modules.dev_frontend_title": "Frontend-Modul — in 5 Minuten",
    "modules.dev_frontend_intro": "Frontend-Module liegen unter frontend/src/modules/. Jedes exportiert ein Manifest mit Routen, Nav-Items und Übersetzungen. Die Registry verdrahtet sie automatisch in Sidebar und Router.",
    "modules.dev_front_step_folder": "Ordner anlegen",
    "modules.dev_front_step_manifest": "manifest.ts erstellen",
    "modules.dev_front_step_component": "React-Seite bauen",
    "modules.dev_front_step_register": "Registrieren",
    "modules.dev_front_step_i18n": "Übersetzungen hinzufügen",
    "modules.dev_events_title": "Events & Hooks — wie Module miteinander reden",
    "modules.dev_events_intro": "Niemals direkt aus einem anderen Modul importieren. Events senden und abonnieren. So bleiben Module entkoppelt und Installieren/Deaktivieren ist sicher.",
    "modules.dev_events_publish": "Event veröffentlichen",
    "modules.dev_events_subscribe": "In events.py abonnieren",
    "modules.dev_events_known": "Häufige Events, auf die du hören kannst:",
    "modules.dev_perms_title": "Berechtigungen & RBAC",
    "modules.dev_perms_intro": "Deklariere die Berechtigungen, die dein Modul nutzt. Schütze jeden mutierenden Endpoint mit RequirePermission — verlasse dich nie allein darauf, dass der Nutzer angemeldet ist.",
    "modules.dev_perms_step1": "In permissions.py deklarieren",
    "modules.dev_perms_step2": "Routen absichern",
    "modules.dev_perms_roles": "Rollen sind hierarchisch: admin > manager > editor > viewer. Wenn du eine Berechtigung an Role.EDITOR vergibst, bekommen sie automatisch editor + manager + admin — admin umgeht ohnehin alles, du listest ihn also nie explizit. Unbekannte Berechtigungsnamen sind standardmäßig admin-only, was sicher ist, aber selten gewünscht.",
    "modules.dev_test_title": "Modul testen",
    "modules.dev_test_intro": "Tests sind Pflicht in jeder PR. Das Projekt nutzt pytest für Backend, vitest für Frontend und Playwright für E2E. Lokal laufen dieselben Befehle wie in CI.",
    "modules.dev_test_backend": "Backend — pytest",
    "modules.dev_test_frontend": "Frontend — vitest",
    "modules.dev_test_e2e": "E2E — Playwright",
    "modules.dev_test_pattern": "Backend-Tests nutzen httpx + ASGITransport — kein echtes HTTP. Frontend-Tests laufen in jsdom. Geteilte Integrations-Fixtures liegen in backend/tests/integration/_auth_helpers.py.",
    "modules.dev_install_title": "Drittanbieter-Modul installieren",
